use openssl::sha::sha256;

fn combine_hash_list(input: &[&[u8]]) -> Vec<u8> {
    input
        .iter()
        .map(|c| sha256(c).to_vec())
        .collect::<Vec<Vec<u8>>>()
        .concat()
}

