#[test]
fn test_att_matches_iphone() {
    let client_data = {
        let client_data_json =
            base64::decode_config(test_vectors::CLIENT_DATA_JSON_1, base64::URL_SAFE_NO_PAD).unwrap();

        let att_obj = base64::decode_config(test_vectors::ATT_OBJ_1, base64::URL_SAFE_NO_PAD).unwrap();

        let location_match = vec![test_vectors::LOCATION_MATCH_1];

        combine_hash_list(&[
            client_data_json.as_ref(),
            att_obj.as_ref(),
            location_match.as_ref(),
        ])
    };

    let cdh = sha256(&client_data);
    assert_eq!(&base64::encode(cdh), test_vectors::CDH_1);

    let app_attestation = base64::decode_config(test_vectors::APP_ATTEST_1, base64::URL_SAFE_NO_PAD).unwrap();

    let verifier = AppleAppAttestationVerifier::new_default_ca(
        vec![
            "C246BC89CJ.in.alexgr.FootprintVerify",
            "C246BC89CJ.in.alexgr.FootprintVerify.Clip",
        ],
        "doesnt matter",
        "doesnt matter",
        "C246BC89CJ",
    )
    .unwrap();

    let res = verifier
        .attest(&client_data, &app_attestation)
        .expect("failed to verify");
    assert!(res.is_development);
}

#[test]
fn test_att_fails_hash() {
    let app_attestation = base64::decode_config(test_vectors::APP_ATTEST_1, base64::URL_SAFE_NO_PAD).unwrap();

    let verifier = AppleAppAttestationVerifier::new_default_ca(
        vec![
            "C246BC89CJ.in.alexgr.FootprintVerify",
            "C246BC89CJ.in.alexgr.FootprintVerify.Clip",
        ],
        "doesnt matter",
        "doesnt matter",
        "C246BC89CJ",
    )
    .unwrap();

    let client_data = b"some_wrong_client_data_inputs";

    verifier
        .attest(client_data, &app_attestation)
        .expect_err("failed to verify");
}

#[test]
fn test_receipt_parsing() {
    let app_attestation =
        base64::decode_config(tests::test_vectors::APP_ATTEST_1, base64::URL_SAFE_NO_PAD).unwrap();
    let verifier = AppleAppAttestationVerifier::new_default_ca(
        vec![
            "C246BC89CJ.in.alexgr.FootprintVerify",
            "C246BC89CJ.in.alexgr.FootprintVerify.Clip",
        ],
        "doesnt matter",
        "doesnt matter",
        "C246BC89CJ",
    )
    .unwrap();

    let res = verifier
        .attest(
            &base64::decode(tests::test_vectors::CD).unwrap(),
            &app_attestation,
        )
        .expect("failed to verify");

    let receipt = super::device_check::inner_verify_and_parse_receipt(&verifier.config, res.receipt, true)
        .expect("failed");

    assert_eq!(receipt.app_id.as_str(), "C246BC89CJ.in.alexgr.FootprintVerify");
    assert_eq!(receipt.attested_public_key, res.att_public_key);
    assert_eq!(receipt.client_hash, base64::decode(CDH_1).unwrap());
    assert_eq!(receipt.receipt_type, ReceiptType::Attest);
    assert_eq!(
        receipt.token.as_str(),
        "MldjdMkOBi+J7gJPy24BIw91GkV+/tgouIfckEp6Cgwtdz1XjSzh9N0aqGApNAIfd34nmVKfVVr9yNLztoj8/g=="
    );
    assert!(receipt.is_sandbox);
}

