#[ignore]
#[tokio::test]
async fn test_fetch_receipt() {
    let app_attestation = base64::decode(tests::test_vectors::APP_ATTEST_2).unwrap();
    let verifier: AppleAppAttestationVerifier = AppleAppAttestationVerifier::new_default_ca(
        vec![
            "5F264K8AG4.com.onefootprint.my",
            "5F264K8AG4.com.onefootprint.my.Clip",
            "5F264K8AG4.com.onefootprint.demo-swift",
        ],
        // nosemgrep
        "-----BEGIN PRIVATE KEY-----
MIGTAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBHkwdwIBAQQg5dQK1vD+J6BPctWQ
OnQ3z58zG0IrWakPqw6J0Es8k+igCgYIKoZIzj0DAQehRANCAAS/QUqu/nzVEoi/
CIFxdXazwDWRQ1rIBiYULgRNGDXOfVCtT6hWkmtDxD1KYQ4nUhIkd76ubRxk3XxX
qriAvCkH
-----END PRIVATE KEY-----",
        "3A9LZR4SKP",
        "5F264K8AG4",
    )
    .unwrap();
    let res = verifier
        .attest(
            &base64::decode(tests::test_vectors::CD_2).unwrap(),
            &app_attestation,
        )
        .expect("failed to verify");
    let _parsed_receipt = verifier
        .verify_and_parse_receipt(res.receipt.clone())
        .expect("failed to parse receipt");

    let (server_rec, _) = verifier
        .fetch_device_check_receipt(res.is_development, res.receipt)
        .await
        .expect("failed to fetch");

    assert!(server_rec.risk_metric.is_some());
}

#[ignore]
#[tokio::test]
async fn test_fetch_bits() {
    let verifier: AppleAppAttestationVerifier = AppleAppAttestationVerifier::new_default_ca(
        vec![
            "5F264K8AG4.com.onefootprint.my",
            "5F264K8AG4.com.onefootprint.my.Clip",
            "5F264K8AG4.com.onefootprint.demo-swift",
        ],
        "-----BEGIN PRIVATE KEY-----
MIGTAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBHkwdwIBAQQg5dQK1vD+J6BPctWQ
OnQ3z58zG0IrWakPqw6J0Es8k+igCgYIKoZIzj0DAQehRANCAAS/QUqu/nzVEoi/
CIFxdXazwDWRQ1rIBiYULgRNGDXOfVCtT6hWkmtDxD1KYQ4nUhIkd76ubRxk3XxX
qriAvCkH
-----END PRIVATE KEY-----",
        "3A9LZR4SKP",
        "5F264K8AG4",
    )
    .unwrap();

    let token = "".to_string();

    verifier
        .validate_device_token(token.clone(), true)
        .await
        .expect("failed to validate token");

    let _bits = verifier
        .query_device_bits(token.clone(), true)
        .await
        .expect("failed to fetch bits");

    verifier
        .update_device_bits(token.clone(), true, true, false)
        .await
        .expect("failed to update");

    let bits = verifier
        .query_device_bits(token.clone(), true)
        .await
        .expect("failed to fetch bits")
        .expect("bits should be set");

    assert!(bits.bit0);
    assert!(!bits.bit1);
}
